import{_ as s,C as n,o as p,c as h,j as a,a as i,E as t,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"了凡四训·积善之方","description":"第三篇，详解善之真假、端曲、阴阳、是非、偏正、半满、大小、难易，附随缘济众十纲。","frontmatter":{"title":"了凡四训·积善之方","description":"第三篇，详解善之真假、端曲、阴阳、是非、偏正、半满、大小、难易，附随缘济众十纲。","category":"guide","aliases":["积善之方","了凡四训第三篇"],"source":["《了凡四训》"]},"headers":[],"relativePath":"lizhimingde/liaofan-sixun/chapter-03.md","filePath":"lizhimingde/liaofan-sixun/chapter-03.md","lastUpdated":1781102614000}'),c={name:"lizhimingde/liaofan-sixun/chapter-03.md"};function u(g,e,x,b,f,_){const r=n("DaoReadingPrelude"),o=n("DaoOriginalReading"),l=n("DaoLineGuide"),d=n("DaoKeywordCards");return p(),h("div",null,[e[0]||(e[0]=a("h1",{id:"了凡四训·积善之方",tabindex:"-1"},[i("了凡四训·积善之方 "),a("a",{class:"header-anchor",href:"#了凡四训·积善之方","aria-label":'Permalink to "了凡四训·积善之方"'},"​")],-1)),t(r,{title:"积善不是空谈——十条实例与八对辨析",summary:"积善之方是了凡四训中篇幅最长的一篇。了凡先举十条历史实例证明积善必有馀庆，然后深入辨析善的八对范畴（真假、端曲、阴阳、是非、偏正、半满、大小、难易），最后给出随缘济众的十纲（与人为善、爱敬存心、成人之美、劝人为善、救人危急、兴建大利、舍财作福、护持正法、敬重尊长、爱惜物命）。",points:[{label:"实证",text:"十条历史实例——积善之家，必有馀庆。"},{label:"辨析",text:"八对范畴——行善若不明理，枉费苦心。"},{label:"践行",text:"随缘济众十纲——从日用中落实。"}],hint:"这篇较长，建议分段读：先过实例，再品辨析，最后对照十纲检查自身。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),t(o,{tone:"ink",density:"comfortable",defaultMode:"regular",modeSwitch:!1,paragraphs:["易曰：积善之家，必有馀庆。昔颜氏将以女妻叔梁纥，而历叙其祖宗积德之长，逆知其子孙必有兴者。孔子称舜之大孝，曰：宗庙飨之，子孙保之，皆至论也。试以往事徵之。","杨少师荣，建宁人。世以济渡为生，久雨溪涨，横流冲毁民居，溺死者顺流而下，他舟皆捞取货物，独少师曾祖及祖，惟救人，而货物一无所取，乡人嗤其愚。逮少师父生，家渐裕，有神人化为道者，语之曰：汝祖父有阴功，子孙当贵显，宜葬某地。遂依其所指而窆之，即今白兔坟也。后生少师，弱冠登第，位至三公，加曾祖，祖，父，如其官。子孙贵盛，至今尚多贤者。","鄞人杨自惩，初为县吏，存心仁厚，守法公平。时县宰严肃，偶挞一囚，血流满前，而怒犹未息，杨跪而宽解之。宰曰：怎奈此人越法悖理，不由人不怒。自惩叩首曰：上失其道，民散久矣，如得其情，哀矜勿喜；喜且不可，而况怒乎？宰为之霁颜。家甚贫，馈遗一无所取，遇囚人乏粮，常多方以济之。一日，有新囚数人待哺，家又缺米；给囚则家人无食；自顾则囚人堪悯；与其妇商之。妇曰：囚从何来？曰：自杭而来。沿路忍饥，菜色可掬。因撤己之米，煮粥以食囚。后生二子，长曰守陈，次曰守址，为南北吏部侍郎；长孙为刑部侍郎；次孙为四川廉宪，又俱为名臣；今楚亭，德政，亦其裔也。","昔正统间，邓茂七倡乱於福建，士民从贼者甚众；朝廷起鄞县张都宪楷南征，以计擒贼，后委布政司谢都事，搜杀东路贼党；谢求贼中党附册籍，凡不附贼者，密授以白布小旗，约兵至日，插旗门首，戒军兵无妄杀，全活万人；后谢之子迁，中状元，为宰辅；孙丕，复中探花。","莆田林氏，先世有老母好善，常作粉团施人，求取即与之，无倦色；一仙化为道人，每旦索食六七团。母日日与之，终三年如一日，乃知其诚也。因谓之曰：吾食汝三年粉团，何以报汝？府后有一地，葬之，子孙官爵，有一升麻子之数。其子依所点葬之，初世即有九人登第，累代簪缨甚盛，福建有无林不开榜之谣。","冯琢庵太史之父，为邑庠生。隆冬早起赴学，路遇一人，倒卧雪中，扪之，半僵矣。遂解己绵裘衣之，且扶归救苏。梦神告之曰：汝救人一命，出至诚心，吾遣韩琦为汝子。及生琢庵，遂名琦。","台州应尚书，壮年习业於山中。夜鬼啸集，往往惊人，公不惧也；一夕闻鬼云：某妇以夫久客不归，翁姑逼其嫁人。明夜当缢死於此，吾得代矣。公潜卖田，得银四两。即伪作其夫之书，寄银还家；其父母见书，以手迹不类，疑之。既而曰：书可假，银不可假，想儿无恙。妇遂不嫁。其子后归，夫妇相保如初。公又闻鬼语曰：我当得代，奈此秀才坏吾事。旁一鬼曰：尔何不祸之？曰：上帝以此人心好，命作阴德尚书矣，吾何得而祸之？应公因此益自努励，善日加修，德日加厚；遇岁饥，辄捐谷以赈之；遇亲戚有急，辄委曲维持；遇有横逆，辄反躬自责，怡然顺受；子孙登科第者，今累累也。","常熟徐凤竹栻，其父素富，偶遇年荒，先捐租以为同邑之倡，又分谷以赈贫乏，夜闻鬼唱於门曰：千不诓，万不诓；徐家秀才，做到了举人郎。相续而呼，连夜不断。是岁，凤竹果举於乡，其父因而益积德，孳孳不怠，修桥修路，斋僧接众，凡有利益，无不尽心。后又闻鬼唱於门曰：千不诓，万不诓；徐家举人，直做到都堂。凤竹官终两浙巡抚。","喜兴屠康僖公，初为刑部主事，宿狱中，细询诸囚情状，得无辜者若干人，公不自以为功，密疏其事，以白堂官。后朝审，堂官摘其语，以讯诸囚，无不服者，释冤抑十馀人。一时辇下咸颂尚书之明。公复禀曰：辇毂之下，尚多冤民，四海之广，兆民之众，岂无枉者？宜五年差一减刑官，核实而平反之。尚书为奏，允其议。时公亦差减刑之列，梦一神告之曰：汝命无子，今减刑之议，深合天心，上帝赐汝三子，皆衣紫腰金。是夕夫人有娠，后生应埙，应坤，应埈，皆显官。","嘉兴包凭，字信之，其父为池阳太守，生七子，凭最少，赘平湖袁氏，与吾父往来甚厚，博学高才，累举不第，留心二氏之学。一日东游泖湖，偶至一村寺中，见观音像，淋漓露立，即解橐中十金，授主僧，令修屋宇，僧告以功大银少，不能竣事；复取松布四疋，检箧中衣七件与之，内纟宁褶，系新置，其仆请已之。凭曰：但得圣像无恙，吾虽裸裎何伤？僧垂泪曰：舍银及衣布，犹非难事。只此一点心，如何易得。后功完，拉老父同游，宿寺中。公梦伽蓝来曰：汝子当享世禄矣。后子汴，孙柽芳，皆登第，作显官。","嘉善支立之父，为刑房吏，有囚无辜陷重辟，意哀之，欲求其生。囚语其妻曰：支公嘉意，愧无以报，明日延之下乡，汝以身事之，彼或肯用意，则我可生也。其妻泣而听命。及至，妻自出劝酒，具告以夫意。支不听，卒为尽力平反之。囚出狱，夫妻登门叩谢曰：公如此厚德，晚世所稀，今无子，吾有弱女，送为箕帚妾，此则礼之可通者。支为备礼而纳之，生立，弱冠中魁，官至翰林孔目，立生高，高生禄，皆贡为学博。禄生大纶，登第。","凡此十条，所行不同，同归於善而已。若复精而言之，则善有真，有假；有端，有曲；有阴，有阳；有是，有非；有偏，有正；有半，有满；有大，有小；有难，有易；皆当深辨。为善而不穷理，则自谓行持，岂知造孽，枉费苦心，无益也。","何谓真假？昔有儒生数辈，谒中峰和尚，问曰：佛氏论善恶报应，如影随形。今某人善，而子孙不兴；某人恶，而家门隆盛；佛说无稽矣。中峰云：凡情未涤，正眼未开，认善为恶，指恶为善，往往有之。不憾己之是非颠倒，而反怨天之报应有差乎？众曰：善恶何致相反？中峰令试言。一人谓詈人殴人是恶；敬人礼人是善。中峰云：未必然也。一人谓贪财妄取是恶，廉洁有守是善。中峰云：未必然也。众人历言其状，中峰皆谓不然。因请问。中峰告之曰：有益於人，是善；有益於己，是恶。有益於人，则殴人，詈人皆善也；有益於己，则敬人，礼人皆恶也。是故人之行善，利人者公，公则为真；利己者私，私则为假。又根心者真，袭迹者假；又无为而为者真，有为而为者假；皆当自考。","何谓端曲？今人见谨愿之士，类称为善而取之；圣人则宁取狂狷。至於谨愿之士，虽一乡皆好，而必以为德之贼；是世人之善恶，分明与圣人相反。推此一端，种种取舍，无有不谬；天地鬼神之福善祸淫，皆与圣人同是非，而不与世俗同取舍。凡欲积善，决不可徇耳目，惟从心源隐微处，默默洗涤，纯是济世之心，则为端；苟有一毫媚世之心，即为曲；纯是爱人之心，则为端；有一毫愤世之心，即为曲；纯是敬人之心，则为端；有一毫玩世之心，即为曲；皆当细辨。","何谓阴阳？凡为善而人知之，则为阳善；为善而人不知，则为阴德。阴德，天报之；阳善，享世名。名，亦福也。名者，造物所忌；世之享盛名而实不副者，多有奇祸；人之无过咎而横被恶名者，子孙往往骤发，阴阳之际微矣哉。","何谓是非？鲁国之法，鲁人有赎人臣妾於诸侯，皆受金於府，子贡赎人而不受金。孔子闻而恶之曰：赐失之矣。夫圣人举事，可以移风易俗，而教道可施於百姓，非独适己之行也。今鲁国富者寡而贫者众，受金则为不廉，何以相赎乎？自今以后，不复赎人於诸侯矣。子路拯人於溺，其人谢之以牛，子路受之。孔子喜曰：自今鲁国多拯人於溺矣。自俗眼观之，子贡不受金为优，子路之受牛为劣；孔子则取由而黜赐焉。乃知人之为善，不论现行而论流弊；不论一时而论久远；不论一身而论天下。现行虽善，其流足以害人；则似善而实非也；现行虽不善，而其流足以济人，则非善而实是也。然此就一节论之耳。他如非义之义，非礼之礼，非信之信，非慈之慈，皆当抉择。","何谓偏正？昔吕文懿公，初辞相位，归故里，海内仰之，如泰山北斗。有一乡人，醉而詈之，吕公不动，谓其仆曰：醉者勿与较也。闭门谢之。逾年，其人犯死刑入狱。吕公始悔之曰：使当时稍与计较，送公家责治，可以小惩而大戒；吾当时只欲存心於厚，不谓养成其恶，以至於此。此以善心而行恶事者也。又有以恶心而行善事者。如某家大富，值岁荒，穷民白昼抢粟於市；告之县，县不理，穷民愈肆，遂私执而困辱之，众始定；不然，几乱矣。故善者为正，恶者为偏，人皆知之；其以善心行恶事者，正中偏也；以恶心而行善事者，偏中正也；不可不知也。","何谓半满？易曰：善不积，不足以成名；恶不积，不足以灭身。书曰：商罪贯盈，如贮物於器。勤而积之，则满；懈而不积，则不满。此一说也。昔有某氏女入寺，欲施而无财，止有钱二文，捐而与之，主席者亲为忏悔；及后入宫富贵，携数千金入寺舍之，主僧惟令其徒回向而已。因问曰：吾前施钱二文，师亲为忏悔，今施数千金，而师不回向，何也？曰：前者物虽薄，而施心甚真，非老僧亲忏，不足报德；今物虽厚，而施心不若前日之切，令人代忏足矣。此千金为半，而二文为满也。锺离授丹於吕祖，点铁为金，可以济世。吕问曰：终变否？曰：五百年后，当复本质。吕曰：如此则害五百年后人矣，吾不愿为也。曰：修仙要积三千功行，汝此一言，三千功行已满矣。此又一说也。又为善而心不著善，则随所成就，皆得圆满。心著於善，虽终身勤励，止於半善而已。譬如以财济人，内不见己，外不见人，中不见所施之物，是谓三轮体空，是谓一心清净，则斗粟可以种无涯之福，一文可以消千劫之罪，倘此心未忘，虽黄金万镒，福不满也。此又一说也。","何谓大小？昔卫仲达为馆职，被摄至冥司，主者命吏呈善恶二录，比至，则恶录盈庭，其善录一轴，仅如筋而已。索秤称之，则盈庭者反轻，而如筋者反重。仲达曰：某年未四十，安得过恶如是多乎？曰：一念不正即是，不待犯也。因问轴中所书何事？曰：朝廷尝兴大工，修三山石桥，君上疏谏之，此疏稿也。仲达曰：某虽言，朝廷不从，於事无补，而能有如是之力。曰：朝廷虽不从，君之一念，已在万民；向使听从，善力更大矣。故志在天下国家，则善虽少而大；苟在一身，虽多亦小。","何谓难易？先儒谓克己须从难克处克将去。夫子论为仁，亦曰先难。必如江西舒翁，舍二年仅得之束修，代偿官银，而全人夫妇；与邯郸张翁，舍十年所积之钱，代完赎银，而活人妻子，皆所谓难舍处能舍也。如镇江靳翁，虽年老无子，不忍以幼女为妾，而还之邻，此难忍处能忍也；故天降之福亦厚。凡有财有势者，其立德皆易，易而不为，是为自暴。贫贱作福皆难，难而能为，斯可贵耳。","随缘济众，其类至繁，约言其纲，大约有十：第一，与人为善；第二，爱敬存心；第三，成人之美；第四，劝人为善；第五，救人危急；第六，兴建大利；第七，舍财作福；第八，护持正法；第九，敬重尊长；第十，爱惜物命。","何谓与人为善？昔舜在雷泽，见渔者皆取深潭厚泽，而老弱则渔於急流浅滩之中，恻然哀之，往而渔焉；见争者皆匿其过而不谈，见有让者，则揄扬而取法之。期年，皆以深潭厚泽相让矣。夫以舜之明哲，岂不能出一言教众人哉？乃不以言教而以身转之，此良工苦心也。吾辈处未世，勿以己之长而盖人；勿以己之善而形人；勿以己之多能而困人。收敛才智，若无若虚；见人过失，且涵容而掩覆之。一则令其可改，一则令其有所顾忌而不敢纵，见人有微长可取，小善可录，翻然舍己而从之；且为艳称而广述之。凡日用间，发一言，行一事，全不为自己起念，全是为物立则；此大人天下为公之度也。","何谓爱敬存心？君子与小人，就形迹观，常易相混，惟一点存心处，则善恶悬绝，判然如黑白之相反。故曰：君子所以异於人者，以其存心也。君子所存之心，只是爱人敬人之心。盖人有亲疏贵贱，有智愚贤不肖；万品不齐，皆吾同胞，皆吾一体，孰非当敬爱者？爱敬众人，即是爱敬圣贤；能通众人之志，即是通圣贤之志。何者？圣贤志，本欲斯世斯人，各得其所。吾合爱合敬，而安一世之人，即是为圣贤而安之也。","何谓成人之美？玉之在石，抵掷则瓦砾，追琢则圭璋；故凡见人行一善事，或其人志可取而资可进，皆须诱掖而成就之。或为之奖借，或为之维持；或为白其诬而分其谤；务使成立而后已。大抵人各恶其非类，乡人之善者少，不善者多。善人在俗，亦难自立。且豪杰铮铮，不甚修形迹，多易指摘；故善事常易败，而善人常得谤；惟仁人长者，匡直而辅翼之，其功德最宏。","何谓劝人为善？生为人类，孰无良心？世路役役，最易没溺。凡与人相处，当方便提撕，开其迷惑。譬犹长夜大梦，而令之一觉；譬犹久陷烦恼，而拔之清凉，为惠最溥。韩愈云：一时劝人以口，百世劝人以书。较之与人为善，虽有形迹，然对证发药，时有奇效，不可废也；失言失人，当反吾智。","何谓救人危急？患难颠沛，人所时有。偶一遇之，当如恫瘝在身，速为解救。或以一言伸其屈抑；或以多方济其颠连。崔子曰：惠不在大，赴人之急可也。盖仁人之言哉。","何谓兴建大利？小而一乡之内，大而一邑之中，凡有利益，最宜兴建；或开渠导水，或筑堤防患；或修桥梁，以便行旅；或施茶饭，以济饥渴；随缘劝导，协力兴修，勿避嫌疑，勿辞劳怨。","何谓舍财作福？释门万行，以布施为先。所谓布施者，只是舍之一字耳。达者内舍六根，外舍六尘，一切所有，无不舍者。苟非能然，先从财上布施。世人以衣食为命，故财为最重。吾从而舍之，内以破吾之悭，外以济人之急；始而勉强，终则泰然，最可以荡涤私情，袪除执吝。","何谓护持正法？法者，万世生灵之眼目也。不有正法，何以参赞天地？何以裁成万物？何以脱尘离缚？何以经世出世？故凡见圣贤庙貌，经书典籍，皆当敬重而修饬之。至於举扬正法，上报佛恩，尤当勉励。","何谓敬重尊长？家之父兄，国之君长，与凡年高，德高，位高，识高者，皆当加意奉事。在家而奉侍父母，使深爱婉容，柔声下气，习以成性，便是和气格天之本。出而事君，行一事，毋谓君不知而自恣也。刑一人，毋谓君不知而作威也。事君如天，古人格论，此等处最关阴德。试看忠孝之家，子孙未有不绵远而昌盛者，切须慎之。","何谓爱惜物命？凡人之所以为人者，惟此恻隐之心而已；求仁者求此，积德者积此。周礼，孟春之月，牺牲毋用牝。孟子谓君子远庖厨，所以全吾恻隐之心也。故前辈有四不食之戒，谓闻杀不食，见杀不食，自养者不食，专为我杀者不食。学者未能断肉，且当从此戒之。渐渐增进，慈心愈长，不特杀生当戒，蠢动含灵，皆为物命。求丝煮茧，锄地杀虫，念衣食之由来，皆杀彼以自活。故暴殄之孽，当与杀生等。至於手所误伤，足所误践者，不知其几，皆当委曲防之。古诗云：爱鼠常留饭，怜蛾不点灯。何其仁也！善行无穷，不能殚述；由此十事而推广之，则万德可备矣。"]}),t(l,{lines:[{text:"易曰：积善之家，必有馀庆。试以往事徵之。",tone:"总纲 · 以史为证",guide:"开篇引易经奠定基调：积善不是空谈，有历史为证。接下来十个案例，都是真名真姓真事迹——了凡不是讲故事，是摆证据。"},{text:"凡此十条，所行不同，同归於善而已。若复精而言之，则善有真有假……皆当深辨。",tone:"转折 · 辨善",guide:"十条讲完，了凡话锋一转：行善如果不明理，自以为在行善，实际上可能在造孽。接下来他用八对范畴（真假、端曲、阴阳、是非、偏正、半满、大小、难易）一一破开对善的粗糙认知。"},{text:"有益於人，是善；有益於己，是恶。",tone:"核心 · 真假",guide:"这一句是整个八辨的核心。善恶的标准不是表面行为——有益于人的，打人骂人也是善；有益于己的，敬人礼人也是恶。全看发心。"},{text:"凡为善而人知之，则为阳善；为善而人不知，则为阴德。阴德，天报之；阳善，享世名。名，亦福也。名者，造物所忌。",tone:"辨析 · 阴阳",guide:"做了好事被人知道（阳善），赚到的是名声——名声也是福，但名声太盛会招祸。做了好事没人知道（阴德），天自然会回报。所以真正的积善，不是做给人看的。"},{text:"随缘济众，其类至繁，约言其纲，大约有十……",tone:"实践 · 十纲",guide:"从理论到实践，了凡给出十个可操作的类别：与人为善、爱敬存心、成人之美、劝人为善、救人危急、兴建大利、舍财作福、护持正法、敬重尊长、爱惜物命。不用全做，从其中一两条开始即可。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),t(d,{items:[{term:"阴德",pinyin:["yīn","dé"],meaning:"做了善事而人不自知，称为阴德。与阳善（人尽皆知的善行）相对。了凡认为阴德比阳善更厚——因为不求回报、不图名声的善，心得最真。"},{term:"三轮体空",pinyin:["sān","lún","tǐ","kōng"],meaning:"佛教术语。布施时，内不见布施的我，外不见受施的人，中不见所施的物——三者皆空。能达到这个境界，一文钱可以消千劫之罪。"},{term:"端曲",pinyin:["duān","qū"],meaning:"端是正直纯粹——纯是济世之心、爱人之心、敬人之心。曲是夹杂私念——有一毫媚世、愤世、玩世之心即为曲。了凡让人从心源隐微处去辨别，而不是看表面行为。"},{term:"偏正",pinyin:["piān","zhèng"],meaning:"善心行恶事（如过于宽厚反养成了对方的恶习）是正中偏；恶心行善事（如严厉制止避免了更大的乱子）是偏中正。不能只看表面动机或结果，要结合来看。"},{term:"半满",pinyin:["bàn","mǎn"],meaning:"心真的话，二文钱是满的；心不够真的话，千金也只是半善。与数量无关，与心的真切程度有关。"},{term:"与人为善",pinyin:["yǔ","rén","wéi","shàn"],meaning:"不是对人好的意思，而是以身作则带动他人。舜在雷泽见渔者相争，不是去说教，而是自己去做示范——以身转之，不以言教。"},{term:"成人之美",pinyin:["chéng","rén","zhī","měi"],meaning:"看到别人做好事、有善志，就去帮助他完成。就像玉在石中，需要人去琢磨。善事常易败、善人常得谤，所以需要有人匡扶。"},{term:"爱惜物命",pinyin:["ài","xī","wù","mìng"],meaning:"恻隐之心是人与禽兽的分界。从四不食之戒（闻杀不食、见杀不食、自养不食、特为我杀不食）开始，逐渐扩展到一切生命。"}]}),e[3]||(e[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一篇在说什么" tabindex="-1">象：这一篇在说什么 <a class="header-anchor" href="#象-这一篇在说什么" aria-label="Permalink to &quot;象：这一篇在说什么&quot;">​</a></h3><p>积善之方是了凡四训中篇幅最长的一篇，核心就四个字：明理积善。了凡先用十条历史实例证明积善有效，然后笔锋一转——你以为你在行善，可能恰恰是在造孽。如果不加分辨，善和恶之间的界限远比你以为的模糊。</p><p>他用八对范畴逼你面对一个事实：行善不是做了就算，还要看动机（真假）、看纯度（端曲）、看是否求名（阴阳）、看长远影响（是非）、看综合效果（偏正）、看心态（半满）、看格局（大小）、看难度（难易）。</p><p>最后给出随缘济众十纲，把辨析清了的善，落到可以做的事上。</p><h3 id="理-为什么这一篇重要" tabindex="-1">理：为什么这一篇重要 <a class="header-anchor" href="#理-为什么这一篇重要" aria-label="Permalink to &quot;理：为什么这一篇重要&quot;">​</a></h3><p>这一篇最重要的贡献，是破除了人们对善的粗糙认知。很多人失败在：做了自以为对的善事，却不知道为什么没有好结果。了凡的答案是——你做的可能根本不是善，或者只是半善、假善、曲善。</p><p>有益于人，是善；有益于己，是恶。这一句话就把善恶拉回到发心上。不在于你做了什么，而在于你为什么做、做给谁看、做到什么程度。</p><p>换一个角度说，这一篇的本质是：让你从一个自以为在行善的人，变成一个真正看清善的人。这个转变本身就是修行。</p><h3 id="用-今天怎么进入这一篇" tabindex="-1">用：今天怎么进入这一篇 <a class="header-anchor" href="#用-今天怎么进入这一篇" aria-label="Permalink to &quot;用：今天怎么进入这一篇&quot;">​</a></h3><p>八对范畴虽然多，但可以一个一个来。先从真假入手：回想你最近做过的一件自认为是好事的事——是真想帮人，还是有其他动机？比如做了之后希望别人感谢你、认可你、回报你？如果有，那只是半善。</p><p>然后再看阴阳：你做了好事之后，有没有想让更多人知道？如果有，那是阳善——赚名声无可厚非，但要明白，这和阴德是两种不同的东西，带来的回报也不同。</p><p>最后从十纲里挑一条来练，比如爱惜物命——从这周少点一份肉开始，或者与人为善——试着在工作中不用嘴教人，而是自己先做出来给人看。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>积善这件事，最难的地方不在于不做坏事，而在于你做的好事是不是真的好。很多人一辈子在做好事，但心态不对——做完等着表扬、做完计较回报、做完看不起没做的人。了凡说这些都是假善——做的事是善的，心不是。</p><p>真正积善的人，做完了自己都忘了。不求人知、不求回报、不觉得做了什么了不起的事。对他来说，帮人就跟自己吃饭一样自然。这个境界很难，但至少可以先从少一点表演、多一点真心开始。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p>',18))])}const k=s(c,[["render",u]]);export{P as __pageData,k as default};
